import { mkdir, readFile, readdir, writeFile } from "node:fs/promises";
import path from "node:path";
import process from "node:process";

const root = process.cwd();
const checkOnly = process.argv.includes("--check");
const generatedHeader =
  "// Generated by scripts/generate-contracts.mjs. Do not edit by hand.";

async function readJson(relativePath) {
  const source = await readFile(path.join(root, relativePath), "utf8");
  return JSON.parse(source);
}

function stableJson(value) {
  return `${JSON.stringify(value, null, 2)}\n`;
}

async function writeGenerated(relativePath, content) {
  const target = path.join(root, relativePath);
  if (checkOnly) {
    let current = "";
    try {
      current = await readFile(target, "utf8");
    } catch {
      throw new Error(`Missing generated artifact: ${relativePath}`);
    }
    if (current !== content) {
      throw new Error(`Generated artifact is stale: ${relativePath}`);
    }
    return;
  }

  await mkdir(path.dirname(target), { recursive: true });
  await writeFile(target, content);
}

function assertSemver(version, label) {
  if (!/^\d+\.\d+\.\d+$/.test(version)) {
    throw new Error(`${label} must use semantic version x.y.z`);
  }
}

function operationEntries(openapi) {
  const entries = [];
  for (const [route, pathItem] of Object.entries(openapi.paths ?? {})) {
    for (const method of ["get", "post", "put", "patch", "delete"]) {
      const operation = pathItem[method];
      if (!operation) continue;
      if (!operation.operationId) {
        throw new Error(
          `${method.toUpperCase()} ${route} is missing operationId`,
        );
      }
      entries.push({
        operationId: operation.operationId,
        method: method.toUpperCase(),
        path: route,
        tags: operation.tags ?? [],
      });
    }
  }
  return entries.sort((left, right) =>
    left.operationId.localeCompare(right.operationId),
  );
}

function makeApiClient(openapi) {
  const operations = operationEntries(openapi);
  const methodBlocks = operations
    .map((operation) => {
      return `  ${operation.operationId}(options: TaskOtterRequestOptions = {}) {\n    return this.request(${JSON.stringify(operation.method)}, ${JSON.stringify(operation.path)}, options);\n  }`;
    })
    .join("\n\n");

  return `${generatedHeader}

export const controlPlaneContract = ${JSON.stringify(
    {
      title: openapi.info.title,
      version: openapi.info.version,
      basePath: openapi.servers?.[0]?.url ?? "/api/v1",
      operations,
    },
    null,
    2,
  )} as const;

export type TaskOtterRequestOptions = {
  path?: Record<string, string>;
  query?: Record<string, string | number | boolean | undefined>;
  headers?: Record<string, string>;
  body?: unknown;
};

export type TaskOtterFetch = (input: string, init: {
  method: string;
  headers: Record<string, string>;
  body?: string;
}) => Promise<{
  ok: boolean;
  status: number;
  text: () => Promise<string>;
}>;

export class TaskOtterApiError extends Error {
  readonly status: number;
  readonly response: unknown;

  constructor(status: number, response: unknown) {
    super(\`TaskOtter API request failed with status \${status}\`);
    this.status = status;
    this.response = response;
  }
}

export class TaskOtterClient {
  readonly baseUrl: string;
  readonly fetchImpl: TaskOtterFetch;

  constructor(options: { baseUrl?: string; fetch?: TaskOtterFetch } = {}) {
    this.baseUrl = options.baseUrl ?? controlPlaneContract.basePath;
    this.fetchImpl = options.fetch ?? fetch;
  }

${methodBlocks}

  async request(method: string, route: string, options: TaskOtterRequestOptions = {}): Promise<unknown> {
    const url = this.buildUrl(route, options);
    const query = new URLSearchParams();
    for (const [key, value] of Object.entries(options.query ?? {})) {
      if (value !== undefined) query.set(key, String(value));
    }
    const requestUrl = query.size === 0 ? url : \`\${url}?\${query.toString()}\`;

    const headers = {
      accept: "application/json",
      ...(options.body === undefined ? {} : { "content-type": "application/json" }),
      ...(options.headers ?? {})
    };

    const response = await this.fetchImpl(requestUrl, {
      method,
      headers,
      ...(options.body === undefined ? {} : { body: JSON.stringify(options.body) })
    });
    const responseText = await response.text();
    const parsed = responseText.length === 0 ? undefined : JSON.parse(responseText);
    if (!response.ok) throw new TaskOtterApiError(response.status, parsed);
    return parsed;
  }

  private interpolatePath(route: string, params: Record<string, string> = {}): string {
    return route.replace(/\\{([^}]+)\\}/g, (_match, name) => {
      const value = params[name];
      if (!value) throw new Error(\`Missing path parameter: \${name}\`);
      return encodeURIComponent(value);
    });
  }

  private buildUrl(route: string, options: TaskOtterRequestOptions): string {
    const base = this.baseUrl.replace(/\\/$/, "");
    const path = this.interpolatePath(route, options.path);
    if (base.length === 0) return path;
    return \`\${base}\${path.startsWith("/") ? path : \`/\${path}\`}\`;
  }
}
`;
}

function schemaExportName(fileName) {
  return fileName
    .replace(/\.schema\.json$/, "")
    .split(/[-_]/)
    .map((part) => `${part[0].toUpperCase()}${part.slice(1)}`)
    .join("");
}

async function main() {
  const openapi = await readJson(
    "contracts/openapi/taskotter-control-plane.openapi.json",
  );
  assertSemver(openapi.info.version, "OpenAPI info.version");

  const schemaDir = path.join(root, "contracts/schemas");
  const schemaFileNames = (await readdir(schemaDir))
    .filter((fileName) => fileName.endsWith(".schema.json"))
    .sort();

  const schemaExports = [];
  for (const fileName of schemaFileNames) {
    const schema = await readJson(`contracts/schemas/${fileName}`);
    const schemaVersionConst = schema.properties?.schema_version?.const;
    const envelopeVersionConst = schema.properties?.version?.const;
    const hasVersionedSchema =
      (schemaVersionConst && /@\d+\.\d+\.\d+$/.test(schemaVersionConst)) ||
      (envelopeVersionConst && /^\d+\.\d+\.\d+$/.test(envelopeVersionConst)) ||
      fileName === "event-envelope.schema.json";
    if (!hasVersionedSchema) {
      throw new Error(
        `${fileName} must declare schema_version @x.y.z, envelope version x.y.z, or be the generic event envelope`,
      );
    }

    await writeGenerated(
      `packages/schemas/json/${fileName}`,
      stableJson(schema),
    );
    const exportName = `${schemaExportName(fileName)}Schema`;
    schemaExports.push({ exportName, fileName, schema });
  }

  const schemaIndex = `${generatedHeader}

${schemaExports.map(({ exportName, schema }) => `export const ${exportName} = ${JSON.stringify(schema, null, 2)} as const;`).join("\n\n")}

export const contractSchemas = {
${schemaExports.map(({ exportName, fileName }) => `  ${JSON.stringify(fileName)}: ${exportName}`).join(",\n")}
} as const;
`;

  await writeGenerated("packages/schemas/src/index.ts", schemaIndex);
  await writeGenerated(
    "packages/api-client/src/index.ts",
    makeApiClient(openapi),
  );
}

main().catch((error) => {
  console.error(error.message);
  process.exit(1);
});
